def _token_positions(
    self, tokens: Sequence[int], *, token_bytes: list[bytes] | None = None
) -> list[int]:
    """Returns the starting character position of each token in the original text.

    If UTF-8 character boundaries do not line up with token boundaries, the position is the
    index of the first character that contains bytes from the token.
    """
    if token_bytes is None:
        token_bytes = self.decode_tokens_bytes(tokens)

    text_len = 0
    positions = []
    for token in token_bytes:
        positions.append(max(0, text_len - (0x80 <= token[0] < 0xC0)))
        text_len += sum(1 for c in token if not 0x80 <= c < 0xC0)
    return positions

